import json

class JSONObject:
    """
    Base class for parsing and creating JSON objects.
    """
    def __init__(self, data=None):
        self.data = data or {}

    def to_json(self):
        """
        Converts the object to a JSON string.
        """
        return json.dumps(self.data)

    def from_json(self, json_string):
        """
        Creates a new instance of the class from a JSON string.
        """
        self.__init__(json.loads(json_string))

    def __repr__(self):
        return json.dumps(self.data, indent=4)


class JSONFactoryRegistry:
    """
    Registry of factory functions, keyed by ID.
    """
    def __init__(self):
        self.registry = {}

    def add_factory(self, id, factory_function):
        """
        Adds a new factory function to the registry.
        """
        self.registry[id] = factory_function

    def create_instance(self, id, json_string):
        """
        Creates a new instance of a subclass using the factory function
        associated with a given ID.
        """
        if id in self.registry:
            factory_function = self.registry[id]
            return factory_function(json_string)
        else:
            raise ValueError(f"No factory function found for ID: {id}")


# Example Usage and Registry Initialization
if __name__ == '__main__':
    registry = JSONFactoryRegistry()

    # Example Factory Functions (Subclasses)
    def create_person(json_string):
        return JSONObject(json.loads(json_string))

    def create_product(json_string):
        return JSONObject(json.loads(json_string))

    # Add Factory Functions to the Registry
    registry.add_factory("person", create_person)
    registry.add_factory("product", create_product)

    # Create Instances using the Registry
    person_json = '{"name": "Alice", "age": 30}'
    person = registry.create_instance("person", person_json)
    print(f"Person: {person}")

    product_json = '{"id": 123, "name": "Laptop", "price": 1200}'
    product = registry.create_instance("product", product_json)
    print(f"Product: {product}")
