    """
    Parses a string and returns an object with attributes: type, intensity, size, generation, and choice.
    Raises ValueError if the input string is invalid.
    """
    try:
        parts = input_string.split(',')
        if len(parts) != 5:
            raise ValueError("Invalid input string format. Expected 5 comma-separated values.")

        type_val = int(parts[0])
        intensity_val = int(parts[1])
        size_val = int(parts[2])
        generation_val = int(parts[3])
        choice_val = parts[4].strip()  # Remove leading/trailing whitespace

        return {
            "type": type_val,
            "intensity": intensity_val,
            "size": size_val,
            "generation": generation_val,
            "choice": choice_val
        }
    except ValueError as e:
        raise ValueError(f"Invalid input string: {e}") from None
    except Exception as e:
        raise ValueError(f"An unexpected error occurred: {e}") from None

