import yaml

def load_yaml_config(config_path=None, example_file='config.yaml'):
    """
    Loads a YAML configuration file from a specified path or defaults to a provided example file.

    Args:
        config_path (str, optional): The path to the YAML configuration file. Defaults to None.
        example_file (str, optional): The path to the example YAML file to use if config_path is None. Defaults to 'config.yaml'.

    Returns:
        dict: A dictionary representation of the YAML data.
    """
    if config_path:
        try:
            with open(config_path, 'r') as f:
                return yaml.safe_load(f)
        except FileNotFoundError:
            print(f"Error: Configuration file not found at {config_path}. Using example file: {example_file}")
            return yaml.safe_load(example_file)
        except yaml.YAMLError as e:
            print(f"Error parsing YAML file: {e}. Using example file: {example_file}")
            return yaml.safe_load(example_file)
    else:
        try:
            with open(example_file, 'r') as f:
                return yaml.safe_load(f)
        except FileNotFoundError:
            print(f"Error: Example file not found at {example_file}.  Please provide a valid config_path.")
            return {}
        except yaml.YAMLError as e:
            print(f"Error parsing YAML file: {e}")
            return {}

