CREATE OR REPLACE FUNCTION test_lock_insert()
RETURNS INT AS $$
DECLARE
  rows_affected INT := 0;
BEGIN
  -- Create a table with an auto-incrementing primary key
  CREATE TABLE test_table (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(255)
  );

  -- Insert two rows with unique names
  INSERT INTO test_table (name) VALUES ('Alice');
  INSERT INTO test_table (name) VALUES ('Bob');
  rows_affected := rows_affected + 2;

  -- Acquire a write lock on the table using a given lock name
  LOCK TABLE test_table WRITE 'my_lock';

  -- Insert a third row with a name that is not unique
  INSERT INTO test_table (name) VALUES ('Alice');
  rows_affected := rows_affected + 1;

  -- Release the lock
  UNLOCK TABLES;

  RETURN rows_affected;
END;
$$ LANGUAGE plpgsql;
