def execute_command(command, mode='r', encoding='utf-8'):
    """
    Executes a command using the subprocess module and returns the output as a TextIOWrapper object.

    Args:
        command (str): The command to execute.
        mode (str, optional): The mode of the file to open ('r' for reading, 'w' for writing). Defaults to 'r'.
        encoding (str, optional): The encoding to use when reading or writing. Defaults to 'utf-8'.

    Returns:
        TextIOWrapper: A TextIOWrapper object containing the output of the command.
    """
    try:
        process = subprocess.Popen(command, shell=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        stdout, stderr = process.communicate(timeout=10)  # Added timeout to prevent indefinite blocking

        if process.returncode != 0:
            print(f"Command failed with return code {process.returncode}")
            print(f"Error output: {stderr.decode(encoding)}")
            raise subprocess.CalledProcessError(process.returncode, command, output=stderr.decode(encoding), stderr=stderr.decode(encoding))

        if mode == 'r':
            return io.TextIOWrapper(stdout, encoding=encoding)
        elif mode == 'w':
            return io.TextIOWrapper(stdout, encoding=encoding)
        else:
            raise ValueError("Invalid mode.  Must be 'r' or 'w'.")
    except subprocess.CalledProcessError as e:
        return e.output
    except Exception as e:
        print(f"An error occurred: {e}")
        return None
