CREATE OR REPLACE FUNCTION rename_column_and_add_column(
    table_name VARCHAR(255),
    old_column_name VARCHAR(255),
    new_column_name VARCHAR(255),
    field_object JSON
)
RETURNS VOID
AS $$
DECLARE
    column_definition TEXT;
    sql_statement TEXT;
BEGIN
    -- Construct the column definition based on the JSON object
    column_definition := JSON_OBJECT(
        'data_type' => JSON_EXTRACT_SCALAR(field_object, '$.data_type'),
        'constraints' => JSON_EXTRACT_SCALAR(field_object, '$.constraints')
    );

    -- Construct the ALTER TABLE statement
    sql_statement := 'ALTER TABLE ' || table_name || '
    ' || 'DROP COLUMN ' || old_column_name || ';
    ' || 'ALTER TABLE ' || table_name || '
    ' || 'ADD COLUMN ' || new_column_name || ' ' || column_definition || ';';

    -- Execute the SQL statement
    EXECUTE sql_statement;

END;
$$ LANGUAGE plpgsql;
