import re

def extract_version_and_populate_metadata(file_path, metadata_dict_name):
    """
    Reads a text file, extracts the version number from a specific line,
    and uses that version number to populate a dictionary of metadata for a
    software package.

    Args:
        file_path (str): The path to the text file.
        metadata_dict_name (str): The name of the metadata dictionary to populate.

    Returns:
        dict: The populated dictionary with version information.
    """
    try:
        with open(file_path, 'r') as f:
            for line in f:
                if "Version:" in line:
                    match = re.search(r'\d+(\.\d+)+', line)
                    if match:
                        version = match.group(0)
                        metadata_dict = globals()[metadata_dict_name]
                        metadata_dict['version'] = version
                        break
    except FileNotFoundError:
        print(f"Error: File not found at {file_path}")
        return {}
    except Exception as e:
        print(f"An error occurred: {e}")
        return {}
    return {}
