import os
import sys

class CommandError(Exception):
    pass

class Save:
    def __init__(self, filepath):
        self.filepath = filepath

    def save(self, data):
        try:
            with open(self.filepath, 'w') as f:
                f.write(data)
            return True
        except Exception as e:
            raise CommandError(f"Failed to save file: {e}")

@contextlib.contextmanager
def save_context(save_obj, data):
    try:
        save_obj.save(data)
        yield
    except CommandError as e:
        raise e
    finally:
        pass

def create_and_save(filepath, data):
    """
    Creates a save.Save() object, configures it to save a file to a given path,
    and then uses a context manager to execute a command that saves the file
    using the save.Save() object. Raises a CommandError if the save operation fails.
    """
    save_instance = Save(filepath)
    with save_context(save_instance, data) as _:
        pass
    return True

if __name__ == '__main__':
    # Example Usage
    filepath = "test_file.txt"
    data = "This is some data to save."

    try:
        create_and_save(filepath, data)
        print(f"File saved successfully to {filepath}")
    except CommandError as e:
        print(f"Error: {e}")

    # Example of error handling
    try:
        create_and_save("error_file.txt", "This will fail")
    except CommandError as e:
        print(f"Caught expected error: {e}")
