import os
import subprocess

def get_mercurial_change_info(hg_path, changeset_id):
    """
    Retrieves information about a Mercurial changeset.

    Args:
        hg_path: Path to the Mercurial executable.
        changeset_id: The ID of the changeset to retrieve information for.

    Returns:
        A dictionary containing the changeset information, or None if an error occurs.
    """

    try:
        command = [hg_path, 'log', '--rev', changeset_id, '--summary']
        result = subprocess.run(command, capture_output=True, text=True, check=True)
        output = result.stdout.strip()

        if not output:
            return None

        lines = output.splitlines()
        info = {}

        for line in lines:
            if line.startswith('tag:'):
                info['tag'] = line.split(':')[1].strip()
            elif line.startswith('date:'):
                info['date'] = line.split(':')[1].strip()
            elif line.startswith('author:'):
                info['author'] = line.split(':')[1].strip()
            elif line.startswith('parent:'):
                info['parent'] = line.split(':')[1].strip()
            elif line.startswith('comment:'):
                info['comment'] = line.split(':')[1].strip()

        return info

    except subprocess.CalledProcessError as e:
        print(f"Error executing Mercurial command: {e}")
        return None
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return None

if __name__ == '__main__':
    # Replace with the actual path to your Mercurial executable
    hg_executable_path = 'hg'  # Or the full path like '/usr/bin/hg'

    # Replace with the desired changeset ID
    changeset_id_to_query = '12345'  # Example changeset ID

    change_info = get_mercurial_change_info(hg_executable_path, changeset_id_to_query)

    if change_info:
        print("ChangeSet Information:")
        for key, value in change_info.items():
            print(f"  {key}: {value}")
    else:
        print("Could not retrieve change set information.")
