def conditionally_import_module(module_name):
    """
    Conditionally imports a module based on the Python version.

    Args:
        module_name: The name of the module to import.
    """
    try:
        globals()[module_name]
    except ImportError:
        if sys.version_info.major == 3:
            try:
                import importlib
                importlib.import_module(module_name)
            except ImportError as e:
                print(f"Failed to import {module_name} using importlib: {e}")
                raise
        else:
            print(f"Module {module_name} not found.  Please ensure it is installed.")
            raise ImportError(f"Module {module_name} not found")


def my_function():
    """
    A function that might raise different exceptions in different Python versions.
    """
    try:
        conditionally_import_module("requests")
        response = requests.get("https://www.example.com")
        response.raise_for_status()
        print("Request successful!")
    except ImportError as e:
        handle_exception(e, lambda x: print(f"ImportError: {x}"))
    except requests.exceptions.RequestException as e:
        handle_exception(e, lambda x: print(f"RequestException: {x}"))
    except Exception as e:
        handle_exception(e, lambda x: print(f"Unexpected error: {x}"))



if __name__ == '__main__':
    my_function()
