import java.io.BufferedReader;
import java.io.InputStreamReader;

public class AntlrRunner {

    public static void main(String[] args) {
        if (args.length < 3) {
            System.err.println("Usage: java AntlrRunner <directory> <file> <options>");
            System.exit(1);
        }

        String directory = args[0];
        String file = args[1];
        String options = args[2];

        try {
            ProcessBuilder pb = new ProcessBuilder("antlr", directory, file, options.split(" "));
            Process process = pb.start();

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;

            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

            reader.close();
            process.waitFor();

            if (process.exitValue() != 0) {
                System.err.println("ANTLR tool encountered an error.");
            }

        } catch (Exception e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }
}
